from flask import Flask, request, redirect, session, url_for, jsonify
import requests
import json
import secrets
import base64
import hashlib
from urllib.parse import urlencode, urlparse
import time

app = Flask(__name__)
app.secret_key = secrets.token_hex(32)

# Configuration - Replace with your OIDC provider details
OIDC_CONFIG = {
    'issuer': 'https://your-oidc-provider.com',
    'client_id': 'your-client-id',
    'client_secret': 'your-client-secret',
    'redirect_uri': 'http://localhost:5000/callback',
    'scope': 'openid profile email'
}

# Fetch OIDC configuration
def get_oidc_config():
    response = requests.get(f"{OIDC_CONFIG['issuer']}/.well-known/openid-configuration")
    return response.json()

# Generate secure random nonce
def generate_nonce():
    return secrets.token_urlsafe(32)

# Generate PKCE code verifier and challenge
def generate_pkce():
    code_verifier = secrets.token_urlsafe(32)
    code_challenge = base64.urlsafe_b64encode(
        hashlib.sha256(code_verifier.encode()).digest()
    ).decode().rstrip('=')
    return code_verifier, code_challenge

# Start authentication flow
@app.route('/login')
def login():
    oidc_config = get_oidc_config()
    
    # Generate PKCE values
    code_verifier, code_challenge = generate_pkce()
    
    # Generate nonce
    nonce = generate_nonce()
    
    # Store in session
    session['code_verifier'] = code_verifier
    session['nonce'] = nonce
    
    # Build authorization URL
    auth_url = oidc_config['authorization_endpoint']
    params = {
        'response_type': 'code',
        'client_id': OIDC_CONFIG['client_id'],
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'scope': OIDC_CONFIG['scope'],
        'nonce': nonce,
        'code_challenge': code_challenge,
        'code_challenge_method': 'S256'
    }
    
    return redirect(f"{auth_url}?{urlencode(params)}")

# Handle callback
@app.route('/callback')
def callback():
    code = request.args.get('code')
    error = request.args.get('error')
    
    if error:
        return f"Authentication error: {error}", 400
    
    if not code:
        return "No authorization code received", 400
    
    # Exchange code for tokens
    token_url = get_oidc_config()['token_endpoint']
    
    data = {
        'grant_type': 'authorization_code',
        'client_id': OIDC_CONFIG['client_id'],
        'client_secret': OIDC_CONFIG['client_secret'],
        'code': code,
        'redirect_uri': OIDC_CONFIG['redirect_uri'],
        'code_verifier': session.get('code_verifier')
    }
    
    response = requests.post(token_url, data=data)
    
    if response.status_code != 200:
        return "Failed to exchange code for tokens", 400
    
    token_data = response.json()
    
    # Decode ID token
    id_token = token_data.get('id_token')
    if not id_token:
        return "No ID token received", 400
    
    # Split and decode JWT
    try:
        header, payload, signature = id_token.split('.')
        # Add padding if needed
        payload += '=' * (4 - len(payload) % 4)
        decoded_payload = base64.urlsafe_b64decode(payload)
        user_claims = json.loads(decoded_payload)
    except Exception as e:
        return f"Failed to decode ID token: {str(e)}", 400
    
    # Validate nonce
    session_nonce = session.get('nonce')
    if session_nonce and user_claims.get('nonce') != session_nonce:
        return "Nonce validation failed", 400
    
    # Store user info in session
    session['user'] = {
        'sub': user_claims.get('sub'),
        'name': user_claims.get('name'),
        'email': user_claims.get('email'),
        'preferred_username': user_claims.get('preferred_username')
    }
    
    # Clear session
    session.pop('code_verifier', None)
    session.pop('nonce', None)
    
    return redirect(url_for('dashboard'))

# Dashboard route
@app.route('/dashboard')
def dashboard():
    if 'user' not in session:
        return redirect(url_for('login'))
    
    return f"Welcome {session['user']['name']}!"

# Logout
@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('login'))

# Check authentication
@app.route('/api/user')
def get_user():
    if 'user' not in session:
        return jsonify({'authenticated': False}), 401
    
    return jsonify({
        'authenticated': True,
        'user': session['user']
    })

if __name__ == '__main__':
    app.run(debug=True)